def build(self) -> str:
    sql = f"SELECT * FROM {self.table}"
    if self._conditions:
        clauses = []
        for i, (conj, field, op, value) in enumerate(self._conditions):
            if i == 0:
                clauses.append(f"{field} {op} ?")
            else:
                clauses.append(f"{conj} {field} {op} ?")
            self._params.append(value)
        sql += " WHERE " + " ".join(clauses)
    return sql
